// nodes/filterNode.js
import { useState } from 'react';
import { BaseNode, fieldStyle } from './BaseNode';
import { useStore } from '../store';

export const FilterNode = ({ id, data }) => {
  const updateNodeField = useStore((s) => s.updateNodeField);
  const [condition, setCondition] = useState(data?.condition ?? '');
  const [operator, setOperator] = useState(data?.operator ?? 'contains');

  return (
    <BaseNode
      id={id}
      title="Filter"
      icon="🔍"
      accentColor="#fb7185"
      inputs={[{ id: 'input', label: 'input' }]}
      outputs={[
        { id: 'true', label: 'true' },
        { id: 'false', label: 'false' },
      ]}
    >
      <div style={fieldStyle.group}>
        <label style={fieldStyle.label}>Operator</label>
        <select
          style={fieldStyle.select}
          value={operator}
          onChange={(e) => {
            setOperator(e.target.value);
            updateNodeField(id, 'operator', e.target.value);
          }}
        >
          <option value="contains">Contains</option>
          <option value="equals">Equals</option>
          <option value="starts_with">Starts with</option>
          <option value="ends_with">Ends with</option>
          <option value="regex">Regex</option>
        </select>
      </div>
      <div style={fieldStyle.group}>
        <label style={fieldStyle.label}>Value</label>
        <input
          style={fieldStyle.input}
          placeholder="filter value…"
          value={condition}
          onChange={(e) => {
            setCondition(e.target.value);
            updateNodeField(id, 'condition', e.target.value);
          }}
        />
      </div>
    </BaseNode>
  );
};
